  // ── 20 TABLES ──────────────────────────────────────────
  for (let i = 1; i <= 20; i++) {
    await prisma.table.upsert({
      where: { number: i },
      update: {},
      create: { number: i, active: false, currentOrderId: '' }
    });
  }
  console.log('✅ 20 tables créées');

  // ── RÉCAPITULATIF ──────────────────────────────────────
  const byCat = {};
  menuItems.forEach(item => { byCat[item.cat] = (byCat[item.cat] || 0) + 1; });
  console.log('\n📊 Récapitulatif par catégorie :');
  Object.entries(byCat).forEach(([cat, count]) => {
    console.log(`   ${cat.padEnd(20)} ${count} items`);
  });
  console.log(`\n🎉 Total : ${menuItems.length} items · ${Object.keys(byCat).length} catégories`);
